import java.util.Iterator;  
    import sailpoint.object.Identity;  
    import sailpoint.object.QueryOptions;  
    import sailpoint.object.Filter;
    import org.apache.log4j.Logger;
  
    Logger logger = Logger.getLogger("sailpoint.ascension.rules.saml.sso");
    // Get the nameId from the assertionAttributes
    String nameId = (String)assertionAttributes.get("nameId");
    logger.debug("nameId=[" + nameId + "]");
    Identity ident;
   /* Identity ident;
              if(nameId != null) {
                // Lookup the identity based on nameId
                ident = context.getObject(Identity.class, nameId);
            }
            */
    String ownerName = "";
    if(nameId != null && !"".equals(nameId)) {
      QueryOptions ops = new QueryOptions();
      Filter emailFilter = Filter.eq("email", nameId);
      Filter caseFilter = Filter.ignoreCase(emailFilter);
      ops.addFilter(caseFilter);
      Iterator it = context.search(Identity.class, ops, "name");
      if(it != null && it.hasNext()){
         ownerName = it.next()[0];
      }
      sailpoint.tools.Util.flushIterator(it);
      if(ownerName != null && !"".equals(ownerName)) {
        // Lookup the identity based on name
        ident = context.getObjectByName(Identity.class, ownerName);
        logger.debug("identName=[" + ident.getName() + "]");
      }
    }

    return ident;
